</div>
<script>
function checkPyDfQuiz() {
  var score=0,total=3;
  var pd1=document.querySelector('input[name="pd1"]:checked'),pd1f=document.getElementById('pd1-feedback');
  if(pd1&&pd1.id==='pd1b'){pd1f.innerHTML='✅ Correct!';pd1f.style.color='#1a4d1a';score++;}
  else if(pd1){pd1f.innerHTML='❌ Mixed types per column is the key difference.';pd1f.style.color='#d9534f';}
  var pd2=document.querySelector('input[name="pd2"]:checked'),pd2f=document.getElementById('pd2-feedback');
  if(pd2&&pd2.id==='pd2b'){pd2f.innerHTML='✅ Correct! sum() counts True=1 values → 3 fruits.';pd2f.style.color='#1a4d1a';score++;}
  else if(pd2){pd2f.innerHTML='❌ len()=5 (total). sum() counts True values.';pd2f.style.color='#d9534f';}
  var pd3=document.querySelector('input[name="pd3"]:checked'),pd3f=document.getElementById('pd3-feedback');
  if(pd3&&pd3.id==='pd3b'){pd3f.innerHTML='✅ Correct! Default how="inner" = Inner Join.';pd3f.style.color='#1a4d1a';score++;}
  else if(pd3){pd3f.innerHTML='❌ Default is Inner Join. Use how="outer" for all rows.';pd3f.style.color='#d9534f';}
  var res=document.getElementById('py-df-result');
  if(score===total){res.innerHTML='🎉 Week 1 Python completed!';res.style.color='#1a4d1a';markQuizDone('w1_q_dataframes');}
  else{res.innerHTML=score+'/'+total+' correct.';res.style.color='#d9534f';}
}
</script>
